values
  ('1369806e-4ea8-5225-af4b-53d528e72fd4'::uuid, 'b248fb0f-5294-57b4-af76-9938cb3f905c'::uuid, 'maak', 'มาก', 'มาก', 'very / a lot', 'mâak', 'daily', 'You''ll hear and read มาก everywhere: ดีมาก (very good), เผ็ดมาก (very spicy), and discount copy that promises a lot.', '{}'::jsonb),
  ('134aa101-deb6-53f4-ab45-73b08ff1f542'::uuid, '4497309f-83d5-5cfd-ae20-98d182c44e7a'::uuid, 'dii', 'ดี', 'ดี', 'good', 'dii', 'daily', 'You''ll see ดี inside greetings, reviews, and product copy. It is one of the most reusable positive words in beginner Thai.', '{}'::jsonb),
  ('9aa0d234-007d-5705-abe6-013ec5322296'::uuid, '3be425cd-ea3e-5f8a-ab88-b1efae8eb80f'::uuid, 'gin', 'กิน', 'กิน', 'to eat', 'gin', 'food', 'กิน appears everywhere in daily life, from restaurant invitations to questions about what you want to eat.', '{}'::jsonb),
  ('e2ffdcfe-2699-53cb-aa90-ef775738a0b3'::uuid, '4de66997-87a5-56cb-a66f-7b2cce6228ed'::uuid, 'talat', 'ตลาด', 'ตลาด', 'market', 'tà-làat', 'place', 'Markets are everywhere in Thailand. You''ll see ตลาด on signs for night markets, floating markets, and neighborhood markets.', '{}'::jsonb),
  ('689621ae-0664-5f67-abdf-69572aa9cd01'::uuid, '0afff15b-0b20-53d3-ae86-21d3fe37de52'::uuid, 'bin', 'บิน', 'บิน', 'to fly', 'bin', 'transport', 'บิน appears in airport language, travel offers, and casual talk about planes and trips. It also helps you see how reusable the -ิน frame is.', '{}'::jsonb),
  ('89d521e3-4d9b-523d-ac4e-65377bfe9338'::uuid, 'dc5e9698-631e-5ce9-a0da-6c7fb1abd338'::uuid, 'maae', 'แม่', 'แม่', 'mother', 'mâae', 'daily', 'You''ll see แม่ in family words, shop names, and cultural phrases. It also gives you your first look at a vowel written before the consonant.', '{}'::jsonb),
  ('c971805c-561a-5000-a9e8-846afac9e80b'::uuid, '5f706588-560c-598f-ab7a-52a47ecb2015'::uuid, 'raan', 'ร้าน', 'ร้าน', 'shop', 'râan', 'place', 'You''ll see ร้าน everywhere: ร้านกาแฟ, ร้านอาหาร, ร้านยา. Learning it early pays off on almost every street.', '{}'::jsonb),
  ('8888dcb4-b725-5c58-abe7-96cfcb8ab970'::uuid, 'a85af404-45e0-50ae-a491-e082f54018a8'::uuid, 'chut', 'ชุด', 'ชุด', 'set / combo', 'chút', 'food', 'ชุด shows up in set menus, school uniforms, and clothing signs. On menus, it often means a fixed combo or meal set.', '{}'::jsonb),
  ('c7f7eeee-be9c-59ec-a5ca-e993cf2d61c4'::uuid, 'fb4954f1-e326-56e2-a3d1-b4132b60e254'::uuid, 'sip', 'สิบ', 'สิบ', 'ten', 'sìp', 'sign', 'สิบ helps with prices, receipts, and quantity labels. Even one number word gives you real payoff in markets and transit.', '{}'::jsonb),
  ('cc47d33e-ee3d-50dc-a6ce-b3d61029996d'::uuid, '489857d0-a162-5afa-a7bb-c797b5761864'::uuid, 'khao', 'ข้าว', 'ข้าว', 'rice', 'khâao', 'food', 'ข้าว is one of the highest-value food words in Thailand. It appears on menus, in meal names, and in everyday conversation.', '{}'::jsonb),
  ('c771541d-bc22-55d6-ade9-52b9d986cfe2'::uuid, '6a8b53e3-50a0-5db3-a089-a15c56bc01c6'::uuid, 'moo', 'หมู', 'หมู', 'pork', 'mǔu', 'food', 'หมู is everywhere on Thai menus. It is also the cleanest early example of the leading-ห pattern that learners need sooner rather than later.', '{}'::jsonb),
  ('01409ff0-7f6d-54f3-ab1e-8e428d0ca405'::uuid, 'e387c914-ad75-5a7c-a972-cf079418042d'::uuid, 'ahan', 'อาหาร', 'อาหาร', 'food', 'aa-hǎan', 'food', 'อาหาร appears on restaurant signs, food courts, and delivery labels. Once you can read ร้านอาหาร, the street starts feeling more legible.', '{}'::jsonb),
  ('d2faba91-170e-5cef-ad0b-7f3a04ac6143'::uuid, '227b7204-c818-5c7c-ad68-654e72285cd6'::uuid, 'phat', 'ผัด', 'ผัด', 'stir-fry', 'phàt', 'food', 'ผัด appears on some of the most common Thai dishes, from ผัดไทย to vegetable stir-fries. It is one of the highest-value cooking words you can learn.', '{}'::jsonb);

