  ('2b08fe9f-7330-561e-a49c-f0e155dbdd71'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'b248fb0f-5294-57b4-af76-9938cb3f905c'::uuid, 'maak', 1, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"b248fb0f-5294-57b4-af76-9938cb3f905c","slug":"maak","lessonOrdinal":1,"stage":1,"title":"มาก — Your First High-Payoff Word","anchor":{"id":"1369806e-4ea8-5225-af4b-53d528e72fd4","slug":"maak","text":"มาก","meaning":"very / a lot","pronunciation":"mâak","categoryKey":"daily","contextNote":"You''ll hear and read มาก everywhere: ดีมาก (very good), เผ็ดมาก (very spicy), and discount copy that promises a lot.","segments":[{"text":"มา","sound":"maa"},{"text":"ก","sound":"k"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c3faa381-054e-5dd0-a64b-fe084d0afe2e","key":"word-0e21-0e32","text":"มา","meaning":"to come","pronunciation":"maa","categoryKey":"daily","contextNote":"A basic movement verb you will hear in invitations, directions, and casual conversation.","segments":[{"text":"มา","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"c8d1b913-736c-5dcd-a387-f779532f980e","key":"word-0e01-0e32","text":"กา","meaning":"crow / kettle / mark","pronunciation":"gaa","categoryKey":"daily","contextNote":"A compact real word that reuses the same long-aa frame with no extra letters added.","segments":[{"text":"กา","sound":"gaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"d548bc58-bb46-5e64-a208-ccd84400c5b7","key":"word-0e01-0e32-0e01","text":"กาก","meaning":"dregs / residue","pronunciation":"gaak","categoryKey":"daily","contextNote":"A real dictionary word that gives early final-k practice without adding extra glyphs.","segments":[{"text":"กาก","sound":"gaak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"cae6f954-ee78-5cc6-a2f8-377592ff4bfa","key":"word-0e21-0e32-0e21","text":"มาม","meaning":"sound-only practice","pronunciation":"maam","categoryKey":"daily","contextNote":"A clearly flagged pronunciation drill for an otherwise tiny early lesson pool.","segments":[{"text":"มาม","sound":"maam"}],"metadata":{"sourceType":"nonsense"}}}],"newGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]}],"reviewGraphemes":[],"rules":[{"id":"671ddf5e-f429-5a7b-a9a1-f88d61020189","key":"long-aa-right","name":"Long า Stretches Right","shortDescription":"า is written after the consonant and gives you a long aa sound","explanation":"Thai often places vowels around a consonant instead of in a straight line like English. The long vowel า sits to the right of the consonant and stretches the syllable into a clear aa sound.","examples":[{"text":"มาก = mâak"},{"text":"ตา = taa"}]},{"id":"884e5d37-78f3-5c0d-abda-be4ea9b3b8a5","key":"final-k-stop","name":"Final ก Ends in a Stop","shortDescription":"At the end of a syllable, ก closes sharply as a k sound","explanation":"Thai final consonants are often clipped. In มาก, the last ก does not open into a full English g. It closes the syllable with a short unreleased k sound.","examples":[{"text":"มาก = mâak"}]},{"id":"4438b9e5-0dad-5fb9-a65e-f29a4cc6a62a","key":"implied-short-o","name":"Two Bare Consonants Often Add a Short \"o\"","shortDescription":"When Thai stacks two consonants with no written vowel, a short o often appears between them","explanation":"Once you know a few consonants, you can read more than long-vowel forms. In many short Thai syllables, two consonants written together with no vowel sign are read with an implied short o sound between them.","examples":[{"text":"นก = nok"},{"text":"รถ = rot"}]}],"drills":[{"id":"b0af3b43-477d-5797-a482-fc941bb4fbbb","key":"maak-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"m\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ม","isCorrect":true},{"text":"น"},{"text":"ด"}]},{"id":"a0aec10d-b933-52ac-ae60-d65d2f0db0a4","key":"maak-drill-02-recognize","type":"recognize","prompt":"Which symbol makes the long \"aa\" sound?","payload":{},"options":[{"text":"า","isCorrect":true},{"text":"ิ"},{"text":"ี"},{"text":"ั"}]},{"id":"b5470778-c016-50d4-a379-30ba09788aae","key":"maak-drill-03-match","type":"match","prompt":"What does มาก mean?","payload":{},"options":[{"text":"mother"},{"text":"very / a lot","isCorrect":true},{"text":"shop"},{"text":"rice"}]},{"id":"d6132d4b-1e57-5b24-a79c-d02969f8deab","key":"maak-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"very / a lot\"?","payload":{},"options":[{"text":"มาก","isCorrect":true},{"text":"กาม"},{"text":"มกา"},{"text":"ดาก"}]},{"id":"cb5ae9af-f16f-5910-a61b-6723a6b8426c","key":"maak-drill-05-sound","type":"sound","prompt":"How does the final ก sound in มาก?","payload":{},"options":[{"text":"m"},{"text":"k","isCorrect":true},{"text":"g"},{"text":"n"}]},{"id":"15c40127-56bf-5ed3-ab07-b320a84892c8","key":"maak-drill-06-sound","type":"sound","prompt":"If two consonants appear together with no written vowel, what sound often shows up between them?","payload":{},"options":[{"text":"long \"aa\""},{"text":"long \"ee\""},{"text":"short \"o\"","isCorrect":true},{"text":"long \"oo\""}]}]}}'::jsonb, 'b82d76fa7e0bf4fbc83d443b2d072eb85eeeb5bef3342774f31f91949000866f', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('2858cfe0-23c6-5ef7-ab75-58205949476e'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4497309f-83d5-5cfd-ae20-98d182c44e7a'::uuid, 'dii', 2, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4497309f-83d5-5cfd-ae20-98d182c44e7a","slug":"dii","lessonOrdinal":2,"stage":1,"title":"ดี — A Core Word for Good Things","anchor":{"id":"134aa101-deb6-53f4-ab45-73b08ff1f542","slug":"dii","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","contextNote":"You''ll see ดี inside greetings, reviews, and product copy. It is one of the most reusable positive words in beginner Thai.","segments":[{"text":"ดี","sound":"dii"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"da9766d5-9cc7-5389-a981-8f9306e6b805","key":"word-0e14-0e35-0e14","text":"ดีด","meaning":"to flick / pluck","pronunciation":"diit","categoryKey":"daily","segments":[{"text":"ดีด","sound":"diit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"d0ef507d-f79d-5a6e-af15-15389b449c25","key":"word-0e21-0e35","text":"มี","meaning":"to have","pronunciation":"mii","categoryKey":"daily","segments":[{"text":"มี","sound":"mii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"2fb0d7d0-e813-5ed3-a01c-11e7b9cb22cd","key":"word-0e21-0e35-0e14","text":"มีด","meaning":"knife","pronunciation":"miit","categoryKey":"food","segments":[{"text":"มีด","sound":"miit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f932c1d2-de4f-5a71-a5c9-aa0acbd6f665","key":"word-0e14-0e35-0e21-0e32-0e01","text":"ดีมาก","meaning":"very good","pronunciation":"dii maak","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"c3faa381-054e-5dd0-a64b-fe084d0afe2e","key":"word-0e21-0e32","text":"มา","meaning":"to come","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"มา","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"ed1aa82b-1c19-59de-ad16-fcc1669fd68b","key":"word-0e21-0e32-0e01","text":"มาก","meaning":"very / a lot","pronunciation":"maak","categoryKey":"daily","segments":[{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"c8d1b913-736c-5dcd-a387-f779532f980e","key":"word-0e01-0e32","text":"กา","meaning":"crow / kettle / mark","pronunciation":"gaa","categoryKey":"daily","segments":[{"text":"กา","sound":"gaa"}],"metadata":{"sourceType":"real"}}}],"newGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]}],"rules":[{"id":"08d94ec2-a20e-5de1-a856-70fd4d44ffe2","key":"long-ii-above","name":"Long ี Sits Above","shortDescription":"ี is written above the consonant and gives you a long ee sound","explanation":"Thai vowels are often placed above, below, or around the consonant. In ดี, the consonant comes first and the long vowel ี sits above it, so you read ด then stretch into ee.","examples":[{"text":"ดี = dii"},{"text":"สี = sii"}]},{"id":"6d95fd8f-f8f2-57a9-a0e0-6895baa2f935","key":"initial-d-sound","name":"Initial ด Starts Cleanly","shortDescription":"At the start of a syllable, ด gives you a plain d sound","explanation":"Thai consonants can behave differently at the start and the end of a syllable. In ดี, ด is initial, so you read it as a straightforward d sound before the vowel.","examples":[{"text":"ดี = dii"},{"text":"ดา = daa"}]}],"drills":[{"id":"e8605038-8125-5bf0-a42d-a92a76a6065d","key":"dii-drill-01-recognize","type":"recognize","prompt":"Which letter starts with the \"d\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ด","isCorrect":true},{"text":"ม"},{"text":"น"}]},{"id":"c511cbcf-61d9-5c02-a71c-24ca1cfd5e33","key":"dii-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the long \"ee\" sound?","payload":{},"options":[{"text":"ี","isCorrect":true},{"text":"า"},{"text":"ิ"},{"text":"ั"}]},{"id":"44769f12-1ed6-5a6d-afa4-1279fd796379","key":"dii-drill-03-match","type":"match","prompt":"What does ดี mean?","payload":{},"options":[{"text":"good","isCorrect":true},{"text":"road"},{"text":"eat"},{"text":"shop"}]},{"id":"0917c93d-dc41-5020-af12-5b2ec5e09d5d","key":"dii-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"good\"?","payload":{},"options":[{"text":"ดี","isCorrect":true},{"text":"ดิ"},{"text":"ดา"},{"text":"มี"}]},{"id":"a33c2908-8601-5a15-aa02-1d63eeadeb59","key":"dii-drill-05-sound","type":"sound","prompt":"In ดี, where is the vowel written?","payload":{},"options":[{"text":"before the consonant"},{"text":"after the consonant"},{"text":"above the consonant","isCorrect":true},{"text":"below the consonant"}]}]}}'::jsonb, 'f7bfab16cf7447764e22064fb10c6109d15d5300b44a1842e598a26e4564f16a', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9fd4f5c2-b819-551c-ad9a-c00d4ba7b65d'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '3be425cd-ea3e-5f8a-ab88-b1efae8eb80f'::uuid, 'gin', 3, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"3be425cd-ea3e-5f8a-ab88-b1efae8eb80f","slug":"gin","lessonOrdinal":3,"stage":1,"title":"กิน — The Everyday Food Verb","anchor":{"id":"9aa0d234-007d-5705-abe6-013ec5322296","slug":"gin","text":"กิน","meaning":"to eat","pronunciation":"gin","categoryKey":"food","contextNote":"กิน appears everywhere in daily life, from restaurant invitations to questions about what you want to eat.","segments":[{"text":"กิ","sound":"gi"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"d7782977-ee79-5e00-ae86-265f4b4e9034","key":"word-0e19-0e34-0e14","text":"นิด","meaning":"a little bit","pronunciation":"nit","categoryKey":"daily","segments":[{"text":"นิด","sound":"nit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"142df77a-2c8f-5948-af3f-26e5778ff982","key":"word-0e14-0e34-0e19","text":"ดิน","meaning":"soil / earth","pronunciation":"din","categoryKey":"daily","segments":[{"text":"ดิน","sound":"din"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"86538398-e5ca-5917-a618-e7586d124894","key":"word-0e19-0e32","text":"นา","meaning":"rice field","pronunciation":"naa","categoryKey":"place","segments":[{"text":"นา","sound":"naa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"d23e29b9-adb5-5ff0-a665-1a2096af5bc1","key":"word-0e19-0e32-0e21","text":"นาม","meaning":"name / noun","pronunciation":"naam","categoryKey":"sign","segments":[{"text":"นาม","sound":"naam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"d0ef507d-f79d-5a6e-af15-15389b449c25","key":"word-0e21-0e35","text":"มี","meaning":"to have","pronunciation":"mii","categoryKey":"daily","segments":[{"text":"มี","sound":"mii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"c321b707-4346-5fb4-a2ec-ef4ae570730a","key":"word-0e14-0e35","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"2fb0d7d0-e813-5ed3-a01c-11e7b9cb22cd","key":"word-0e21-0e35-0e14","text":"มีด","meaning":"knife","pronunciation":"miit","categoryKey":"food","segments":[{"text":"มีด","sound":"miit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"ed1aa82b-1c19-59de-ad16-fcc1669fd68b","key":"word-0e21-0e32-0e01","text":"มาก","meaning":"very / a lot","pronunciation":"maak","categoryKey":"daily","segments":[{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"real"}}}],"newGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]}],"rules":[{"id":"90dd223e-c255-5285-a129-360e6205288e","key":"short-i-above","name":"Short ิ Sits Above","shortDescription":"The short i vowel appears above the consonant you read first","explanation":"Thai often asks you to scan above the line as you read. In กิน, the consonant ก comes first and the short vowel ิ is written above it, giving you gi before the final consonant closes the syllable.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"}]},{"id":"23dac35f-4b61-566e-a6f9-3ba53bd27a9d","key":"final-n-stays-n","name":"Final น Stays N","shortDescription":"At the end of a syllable, น keeps a clear n sound","explanation":"Not every Thai final consonant gets clipped into a stop. Final น stays nasal and easy to hear, so กิน closes with a clear n sound.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"}]}],"drills":[{"id":"039886d4-14ad-5d4d-a3b4-b8b5dcacec12","key":"gin-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"n\" sound?","payload":{},"options":[{"text":"ก"},{"text":"น","isCorrect":true},{"text":"ด"},{"text":"ม"}]},{"id":"972fb085-b457-5749-a79c-437d4a4536ec","key":"gin-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the short \"i\" sound?","payload":{},"options":[{"text":"ิ","isCorrect":true},{"text":"ี"},{"text":"า"},{"text":"ั"}]},{"id":"7a6c6175-e8ba-5554-adc7-26bebbdd137e","key":"gin-drill-03-match","type":"match","prompt":"What does กิน mean?","payload":{},"options":[{"text":"to eat","isCorrect":true},{"text":"market"},{"text":"ten"},{"text":"fresh"}]},{"id":"9e64189d-5baf-5d61-a29d-2f09f206301d","key":"gin-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"to eat\"?","payload":{},"options":[{"text":"กิน","isCorrect":true},{"text":"กีน"},{"text":"นิก"},{"text":"มิน"}]},{"id":"266b3b73-cd8c-59fc-a698-3e9422669870","key":"gin-drill-05-sound","type":"sound","prompt":"How do you read the end of กิน?","payload":{},"options":[{"text":"gii"},{"text":"gin","isCorrect":true},{"text":"git"},{"text":"gim"}]}]}}'::jsonb, '45542969b6c3a8f84cab80f63120c05dd405459cd7cadb486b344662046ba5bb', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('aa04e55f-f9d0-5f1c-aa13-4dfdf4170fc0'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4de66997-87a5-56cb-a66f-7b2cce6228ed'::uuid, 'talat', 4, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4de66997-87a5-56cb-a66f-7b2cce6228ed","slug":"talat","lessonOrdinal":4,"stage":2,"title":"ตลาด — Read the Market Sign","anchor":{"id":"e2ffdcfe-2699-53cb-aa90-ef775738a0b3","slug":"talat","text":"ตลาด","meaning":"market","pronunciation":"tà-làat","categoryKey":"place","contextNote":"Markets are everywhere in Thailand. You''ll see ตลาด on signs for night markets, floating markets, and neighborhood markets.","segments":[{"text":"ตล","sound":"tà-l"},{"text":"า","sound":"aa"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"85fd9b41-dc44-5bee-a89e-eba19102c6fe","key":"word-0e15-0e25-0e01","text":"ตลก","meaning":"funny","pronunciation":"dta-lok","categoryKey":"daily","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลก","sound":"lok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"d512d636-b40f-5d24-acc3-1e7a586086fc","key":"word-0e15-0e32-0e25","text":"ตาล","meaning":"sugar palm","pronunciation":"dtaan","categoryKey":"daily","segments":[{"text":"ตาล","sound":"dtaan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"ce9a0864-6fa5-5db8-aa3f-620547a527ab","key":"word-0e15-0e32","text":"ตา","meaning":"eye","pronunciation":"dtaa","categoryKey":"daily","segments":[{"text":"ตา","sound":"dtaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f52a4423-3825-5d2f-a688-dd7536f28b92","key":"word-0e25-0e32","text":"ลา","meaning":"to leave","pronunciation":"laa","categoryKey":"daily","segments":[{"text":"ลา","sound":"laa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"b95dc95e-c0a9-5d38-a6a4-2b85377bed24","key":"word-0e15-0e35","text":"ตี","meaning":"to hit","pronunciation":"dtii","categoryKey":"daily","segments":[{"text":"ตี","sound":"dtii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"8bb882a2-df23-530c-ac76-254c1ece38f1","key":"word-0e15-0e32-0e21","text":"ตาม","meaning":"to follow","pronunciation":"dtaam","categoryKey":"daily","segments":[{"text":"ตาม","sound":"dtaam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"5bd76382-990f-518b-a22d-2c2d1a9b68f5","key":"word-0e25-0e21","text":"ลม","meaning":"wind / air","pronunciation":"lom","categoryKey":"daily","segments":[{"text":"ลม","sound":"lom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"6f963964-1641-57fc-a3f1-b1e43e5bc3fa","key":"word-0e25-0e14","text":"ลด","meaning":"to reduce","pronunciation":"lot","categoryKey":"sign","segments":[{"text":"ลด","sound":"lot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"b1e8228c-b6a4-54d2-a459-0b207dc222b1","key":"word-0e15-0e01","text":"ตก","meaning":"to fall","pronunciation":"dtok","categoryKey":"daily","segments":[{"text":"ตก","sound":"dtok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"3237ade6-2a5b-50e9-a5c7-37cbdf3d442d","key":"word-0e21-0e14","text":"มด","meaning":"ant","pronunciation":"mot","categoryKey":"daily","segments":[{"text":"มด","sound":"mot"}],"metadata":{"sourceType":"real"}}}],"newGraphemes":[{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tags":[]}],"rules":[{"id":"b87f5a0a-c8ed-581b-a6ec-928cce42fde3","key":"hidden-vowel-market","name":"Hidden Short \"a\" Vowel","shortDescription":"When two consonants can''t blend, a short \"a\" hides between them","explanation":"In Thai, when two consonants appear next to each other but can''t form a natural cluster, a short \"a\" sound is inserted between them. In ตลาด, the ต and ล can''t blend, so you say \"tà-làat\" not \"tlàat\". This hidden vowel is never written.","examples":[{"text":"ตล = tà-l (hidden \"a\" between ต and ล)"},{"text":"ถนน = thà-nǒn (hidden \"a\" between ถ and น)"}]},{"id":"06f3f841-d7df-5644-a11e-3c5cdebae18c","key":"final-stop-market","name":"Final Consonants are Stopped","shortDescription":"Consonants at the end of a syllable are \"swallowed\"","explanation":"When ด appears at the end of a word, it doesn''t make a full \"d\" sound. Instead, your tongue touches the roof of your mouth but you don''t release it. This is why ตลาด sounds like \"tà-làat\" and not \"tà-làad\".","examples":[{"text":"ตลาด = tà-làat"},{"text":"หมด = mòt"}]}],"drills":[{"id":"02ce9efb-92b9-5876-aef7-7cab864cfe66","key":"talat-drill-01-recognize","type":"recognize","prompt":"Which letter makes the plain \"t\" sound?","payload":{},"options":[{"text":"ถ"},{"text":"ต","isCorrect":true},{"text":"ด"},{"text":"ล"}]},{"id":"8692dc1d-2f3e-5efd-a5d4-b0019e801fa2","key":"talat-drill-02-recognize","type":"recognize","prompt":"Which letter makes the \"l\" sound?","payload":{},"options":[{"text":"ม"},{"text":"น"},{"text":"ล","isCorrect":true},{"text":"ก"}]},{"id":"0ef86fb7-0bfe-50c2-a601-f21c887e9815","key":"talat-drill-03-match","type":"match","prompt":"What does ตลาด mean?","payload":{},"options":[{"text":"road"},{"text":"market","isCorrect":true},{"text":"mother"},{"text":"airport"}]},{"id":"98fee299-f831-5c87-ae8f-1432c5119075","key":"talat-drill-04-sound","type":"sound","prompt":"Why is there an \"a\" between ต and ล in ตลาด?","payload":{},"options":[{"text":"Because it is written but invisible"},{"text":"Because Thai inserts a short \"a\" when the consonants do not blend naturally","isCorrect":true},{"text":"Because the tone mark creates it"},{"text":"Because ล always starts with a vowel"}]},{"id":"67fb27d1-1746-5a08-aec8-8dac1b69edad","key":"talat-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"market\"?","payload":{},"options":[{"text":"ตลาด","isCorrect":true},{"text":"ตาลด"},{"text":"ลาดต"},{"text":"ดาลต"}]}]}}'::jsonb, '677b388570d01ec8e47c85cfc2f79d01baecbf467619d0cf4cd70946c78aa4e6', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('4cd0ebf5-d946-51b1-af06-0011cef5d048'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '0afff15b-0b20-53d3-ae86-21d3fe37de52'::uuid, 'bin', 5, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"0afff15b-0b20-53d3-ae86-21d3fe37de52","slug":"bin","lessonOrdinal":5,"stage":2,"title":"บิน — Reuse the -ิน Pattern","anchor":{"id":"689621ae-0664-5f67-abdf-69572aa9cd01","slug":"bin","text":"บิน","meaning":"to fly","pronunciation":"bin","categoryKey":"transport","contextNote":"บิน appears in airport language, travel offers, and casual talk about planes and trips. It also helps you see how reusable the -ิน frame is.","segments":[{"text":"บิ","sound":"bi"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"0cdff46d-d2ce-57e2-ae77-8a5e3d6dbf7a","key":"word-0e01-0e1a","text":"กบ","meaning":"frog","pronunciation":"gop","categoryKey":"daily","segments":[{"text":"กบ","sound":"gop"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"9097f5cb-6e39-542d-ab00-4606cacae615","key":"word-0e25-0e32-0e1a","text":"ลาบ","meaning":"laab salad","pronunciation":"laap","categoryKey":"food","segments":[{"text":"ลาบ","sound":"laap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"26d4022b-01d5-5d00-ae7b-c10243eebf3b","key":"word-0e14-0e34-0e1a","text":"ดิบ","meaning":"raw / unripe","pronunciation":"dip","categoryKey":"food","segments":[{"text":"ดิบ","sound":"dip"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"82cad9f2-05d2-56aa-a194-fa4c6dfe85ff","key":"word-0e1a-0e35-0e1a","text":"บีบ","meaning":"to squeeze","pronunciation":"biip","categoryKey":"daily","segments":[{"text":"บีบ","sound":"biip"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"43928d42-5009-56d4-aeaf-c3d01a2bffd0","key":"word-0e1a-0e32-0e19","text":"บาน","meaning":"to bloom / open out","pronunciation":"baan","categoryKey":"daily","segments":[{"text":"บาน","sound":"baan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"b64d7172-1785-5bf4-aba4-37cc44d18d39","key":"word-0e1a-0e14","text":"บด","meaning":"to grind","pronunciation":"bot","categoryKey":"food","segments":[{"text":"บด","sound":"bot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"80361b23-0c1c-5fea-a406-7c820e2c35c5","key":"word-0e1a-0e34-0e14-0e32","text":"บิดา","meaning":"father (formal)","pronunciation":"bi-daa","categoryKey":"sign","segments":[{"text":"บิ","sound":"bi"},{"text":"ดา","sound":"daa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"f1c203bb-50b5-5872-a1b8-40cdaae0eb02","key":"word-0e15-0e25-0e32-0e14","text":"ตลาด","meaning":"market","pronunciation":"dta-laat","categoryKey":"place","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลาด","sound":"laat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"85fd9b41-dc44-5bee-a89e-eba19102c6fe","key":"word-0e15-0e25-0e01","text":"ตลก","meaning":"funny","pronunciation":"dta-lok","categoryKey":"daily","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลก","sound":"lok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"c1a868cf-2bdf-5f27-acd2-86fa5162beb3","key":"word-0e01-0e34-0e19","text":"กิน","meaning":"to eat","pronunciation":"gin","categoryKey":"food","segments":[{"text":"กิน","sound":"gin"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c321b707-4346-5fb4-a2ec-ef4ae570730a","key":"word-0e14-0e35","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"6f963964-1641-57fc-a3f1-b1e43e5bc3fa","key":"word-0e25-0e14","text":"ลด","meaning":"to reduce","pronunciation":"lot","categoryKey":"sign","segments":[{"text":"ลด","sound":"lot"}],"metadata":{"sourceType":"real"}}}],"newGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]}],"rules":[{"id":"6346557e-a6a4-5dac-adcd-4617cd7f09a1","key":"initial-b-sound","name":"Initial บ Starts With B","shortDescription":"At the start of a syllable, บ gives you a plain b sound","explanation":"Thai consonants often shift between initial and final positions. In บิน, บ comes first, so it sounds like a clean b before the short vowel and final consonant close the word.","examples":[{"text":"บิน = bin"},{"text":"บา = baa"}]},{"id":"30f160d3-cbb7-5e8f-ae64-9be8c99ff663","key":"in-frame-pattern","name":"The -ิน Frame Repeats","shortDescription":"Once you know a syllable frame, swapping the first consonant unlocks more words","explanation":"กิน, บิน, and similar short words share the same short-i plus final-น frame. Thai gets much easier once you start seeing these reusable patterns instead of single isolated words.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"},{"text":"ดิน = din"}]}],"drills":[{"id":"52738597-5de3-55d7-a39c-34c088805b8d","key":"bin-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"b\" sound at the start?","payload":{},"options":[{"text":"บ","isCorrect":true},{"text":"ด"},{"text":"ม"},{"text":"น"}]},{"id":"524e2383-96d9-5f31-a5c1-4e4d5ae62344","key":"bin-drill-02-match","type":"match","prompt":"What does บิน mean?","payload":{},"options":[{"text":"to fly","isCorrect":true},{"text":"to eat"},{"text":"market"},{"text":"rice"}]},{"id":"2db2aeae-50e6-5409-ac53-a294a0bdec82","key":"bin-drill-03-spot","type":"spot","prompt":"Which Thai spelling means \"to fly\"?","payload":{},"options":[{"text":"บิน","isCorrect":true},{"text":"นบิ"},{"text":"บีน"},{"text":"ดิน"}]},{"id":"7946c7ee-41fe-5b34-acf3-07bd08891c89","key":"bin-drill-04-sound","type":"sound","prompt":"Which word keeps the same -ิน pattern as บิน?","payload":{},"options":[{"text":"กิน","isCorrect":true},{"text":"มาก"},{"text":"แม่"},{"text":"ร้าน"}]},{"id":"349b3282-167a-5e03-ac9d-dc39ff2c806f","key":"bin-drill-05-sound","type":"sound","prompt":"How do you pronounce บิน?","payload":{},"options":[{"text":"bin","isCorrect":true},{"text":"baan"},{"text":"boon"},{"text":"bii"}]}]}}'::jsonb, '11bbb64745ece39e9a049de3b70291f0bb9baab82b2bce57f00f1905f72af969', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('03d24173-40f9-5857-a0f1-59c06a1edb43'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'dc5e9698-631e-5ce9-a0da-6c7fb1abd338'::uuid, 'maae', 6, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"dc5e9698-631e-5ce9-a0da-6c7fb1abd338","slug":"maae","lessonOrdinal":6,"stage":3,"title":"แม่ — Before Vowels and First Tone Marks","anchor":{"id":"89d521e3-4d9b-523d-ac4e-65377bfe9338","slug":"maae","text":"แม่","meaning":"mother","pronunciation":"mâae","categoryKey":"daily","contextNote":"You''ll see แม่ in family words, shop names, and cultural phrases. It also gives you your first look at a vowel written before the consonant.","segments":[{"text":"แม","sound":"mae"},{"text":"่","sound":"tone change"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"0e2abce6-bed9-5ca0-a6b2-e09afc124410","key":"word-0e41-0e15-0e48","text":"แต่","meaning":"but / however","pronunciation":"dtae","categoryKey":"daily","segments":[{"text":"แต่","sound":"dtae"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"a23f7435-c081-54d4-abaa-0287352f280f","key":"word-0e41-0e01-0e48","text":"แก่","meaning":"old","pronunciation":"gae","categoryKey":"daily","segments":[{"text":"แก่","sound":"gae"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"999b600f-d3d2-5d5a-aff6-b0db7661510b","key":"word-0e41-0e14-0e14","text":"แดด","meaning":"sunlight","pronunciation":"daet","categoryKey":"daily","segments":[{"text":"แดด","sound":"daet"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"c336b414-7092-5360-afeb-e00fc28829bf","key":"word-0e41-0e15-0e01","text":"แตก","meaning":"to break","pronunciation":"dtaek","categoryKey":"daily","segments":[{"text":"แตก","sound":"dtaek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"01ce66af-4e79-5b14-a794-033f56ee7e39","key":"word-0e41-0e1a-0e19","text":"แบน","meaning":"flat","pronunciation":"baen","categoryKey":"daily","segments":[{"text":"แบน","sound":"baen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"0b650405-5f9d-5cc0-ad3f-83a853e24962","key":"word-0e1a-0e48-0e19","text":"บ่น","meaning":"to complain","pronunciation":"bon","categoryKey":"daily","segments":[{"text":"บ่น","sound":"bon"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"28b1a975-232b-5c2f-ae30-832858b634ee","key":"word-0e41-0e01","text":"แก","meaning":"you (casual)","pronunciation":"gae","categoryKey":"daily","segments":[{"text":"แก","sound":"gae"}],"metadata":{"sourceType":"real"}}}],"newGraphemes":[{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tags":[]}],"rules":[{"id":"339f3a02-f34d-5263-a796-4d45cd2e4b7f","key":"before-vowels-left","name":"Some Vowels Sit on the Left","shortDescription":"The vowel แ is written before the consonant you pronounce first","explanation":"Thai does not always place vowels after the consonant. In แม่, your eye has to notice แ on the left, then come back to read ม with that vowel sound attached.","examples":[{"text":"แม = mae"},{"text":"แต่ = dtàae"}]},{"id":"c360364a-3f7a-5b8d-a892-563359ef7e9e","key":"mai-ek-tone-mark","name":"Meet Your First Tone Mark","shortDescription":"Tone marks sit above the consonant and change the sound of the whole syllable","explanation":"You do not need the full tone system at once. Start by recognizing that ่ lives above the consonant and changes the word you say. High-frequency sight words make tone marks easier to remember than abstract charts.","examples":[{"text":"แม่ = mâae"},{"text":"แต่ = dtàae"}]}],"drills":[{"id":"5bc9e17a-4a8a-51bb-a316-aa0a0aa74608","key":"maae-drill-01-recognize","type":"recognize","prompt":"Which vowel is written before the consonant?","payload":{},"options":[{"text":"แ","isCorrect":true},{"text":"า"},{"text":"ิ"},{"text":"ี"}]},{"id":"1b86c74a-d1ff-548e-a833-04ecf6f7c281","key":"maae-drill-02-recognize","type":"recognize","prompt":"Which mark is mai ek?","payload":{},"options":[{"text":"่","isCorrect":true},{"text":"้"},{"text":"แ"},{"text":"ั"}]},{"id":"5b514efd-9fe0-52b0-a98d-87af1c9de60c","key":"maae-drill-03-match","type":"match","prompt":"What does แม่ mean?","payload":{},"options":[{"text":"mother","isCorrect":true},{"text":"shop"},{"text":"road"},{"text":"fresh"}]},{"id":"f0776231-13a2-56ed-a053-5092778712f0","key":"maae-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"mother\"?","payload":{},"options":[{"text":"แม่","isCorrect":true},{"text":"แม"},{"text":"มา"},{"text":"แน"}]},{"id":"87008ac4-4fa4-5eda-a86a-fbd12791e726","key":"maae-drill-05-recognize","type":"recognize","prompt":"What changes when you add ่ above แม?","payload":{},"options":[{"text":"the vowel disappears"},{"text":"the tone changes","isCorrect":true},{"text":"the final consonant changes"},{"text":"the word becomes longer"}]}]}}'::jsonb, 'c497bb4bb76b0cc72d7eda665e95366ac9c0c2a7b1dfd3bdbb5d19dde094ff2a', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('54ff1cc4-122f-5a46-a56b-ca7ba4b0bdf9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '5f706588-560c-598f-ab7a-52a47ecb2015'::uuid, 'raan', 7, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"5f706588-560c-598f-ab7a-52a47ecb2015","slug":"raan","lessonOrdinal":7,"stage":3,"title":"ร้าน — The Word on Every Storefront","anchor":{"id":"c971805c-561a-5000-a9e8-846afac9e80b","slug":"raan","text":"ร้าน","meaning":"shop","pronunciation":"râan","categoryKey":"place","contextNote":"You''ll see ร้าน everywhere: ร้านกาแฟ, ร้านอาหาร, ร้านยา. Learning it early pays off on almost every street.","segments":[{"text":"ร้า","sound":"raa"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"6a66a60f-c509-56f7-a54b-bd44a4028c40","key":"word-0e21-0e49-0e32","text":"ม้า","meaning":"horse","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"ม้า","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"78377bc9-780c-569b-af55-a4e43492b8ac","key":"word-0e1a-0e49-0e32-0e19","text":"บ้าน","meaning":"house / home","pronunciation":"baan","categoryKey":"place","segments":[{"text":"บ้าน","sound":"baan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"c328a5e5-6749-5e36-acd0-170fffcf5e4d","key":"word-0e19-0e49-0e32","text":"น้า","meaning":"aunt / uncle","pronunciation":"naa","categoryKey":"daily","segments":[{"text":"น้า","sound":"naa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"8af6bfe1-3b05-5ada-a070-0cafba9b65be","key":"word-0e14-0e49-0e32-0e19","text":"ด้าน","meaning":"side / aspect","pronunciation":"daan","categoryKey":"sign","segments":[{"text":"ด้าน","sound":"daan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"cccd4ff6-3438-5676-ac28-90cf88fa8941","key":"word-0e23-0e32-0e14","text":"ราด","meaning":"to pour over","pronunciation":"raat","categoryKey":"food","segments":[{"text":"ราด","sound":"raat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"c56de297-1a8f-5f2e-a9ba-5345ef5540bc","key":"word-0e23-0e35-0e14","text":"รีด","meaning":"to iron","pronunciation":"riit","categoryKey":"daily","segments":[{"text":"รีด","sound":"riit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"2498f294-f413-5697-a418-9ede9e739f4b","key":"word-0e23-0e14","text":"รด","meaning":"to water","pronunciation":"rot","categoryKey":"daily","segments":[{"text":"รด","sound":"rot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"d5e43ad2-f9f4-5a78-ac14-995f15b83169","key":"word-0e23-0e49-0e32-0e19-0e14-0e35","text":"ร้านดี","meaning":"good shop","pronunciation":"raan dii","categoryKey":"place","segments":[{"text":"ร้าน","sound":"raan"},{"text":"ดี","sound":"dii"}],"metadata":{"sourceType":"phrase"}}}],"newGraphemes":[{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tags":[]}],"rules":[{"id":"ba8c4da3-023b-5812-a6fb-0c09b52ce472","key":"initial-r-sound","name":"Initial ร Gives You R","shortDescription":"At the start of a syllable, ร is read as an r sound","explanation":"Thai ร has a few different jobs, but in ร้าน it is straightforward: it starts the word with an r sound before the tone mark and vowel shape do the rest of the work.","examples":[{"text":"รา = raa"},{"text":"ร้าน = râan"}]},{"id":"9d39de17-63e6-5cde-a43b-0d5655df93ec","key":"mai-tho-above","name":"Tone Marks Sit Above the Consonant","shortDescription":"Even when the vowel is on the right, the tone mark still sits above the main consonant","explanation":"In ร้าน, the long vowel า is on the right, but the tone mark ้ still sits above ร. Thai asks you to scan the whole syllable block, not just read from left to right.","examples":[{"text":"ร้า = râa"},{"text":"ร้าน = râan"}]}],"drills":[{"id":"7552ce0b-c30c-52bc-a88e-872c25d657d5","key":"raan-drill-01-recognize","type":"recognize","prompt":"Which letter starts with the \"r\" sound?","payload":{},"options":[{"text":"ร","isCorrect":true},{"text":"ล"},{"text":"น"},{"text":"ม"}]},{"id":"de5ad6bb-5b0c-5ede-a4f5-6266b4601f04","key":"raan-drill-02-recognize","type":"recognize","prompt":"Which mark is mai tho?","payload":{},"options":[{"text":"่"},{"text":"้","isCorrect":true},{"text":"ี"},{"text":"แ"}]},{"id":"565b7d5e-735f-5050-ad09-71fed55ac6a7","key":"raan-drill-03-match","type":"match","prompt":"What does ร้าน mean?","payload":{},"options":[{"text":"mother"},{"text":"shop","isCorrect":true},{"text":"ten"},{"text":"very"}]},{"id":"d7002b7d-1e35-5a0f-ae7e-e26a33f09a90","key":"raan-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"shop\"?","payload":{},"options":[{"text":"ร้าน","isCorrect":true},{"text":"ร่าน"},{"text":"ราน"},{"text":"น้าร"}]},{"id":"29a3d27f-d998-532c-abcd-12564e689931","key":"raan-drill-05-sound","type":"sound","prompt":"Where is the tone mark written in ร้าน?","payload":{},"options":[{"text":"under the consonant"},{"text":"above the consonant","isCorrect":true},{"text":"before the vowel"},{"text":"after the final consonant"}]}]}}'::jsonb, 'eacb838f671ff872d372c334525651d6c8ca1900c92a40ce4e41103f88b65ec8', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b54e0d58-84f8-5ea6-a75a-6e3fa02991c2'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'a85af404-45e0-50ae-a491-e082f54018a8'::uuid, 'chut', 8, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"a85af404-45e0-50ae-a491-e082f54018a8","slug":"chut","lessonOrdinal":8,"stage":4,"title":"ชุด — Short U in Menu Combos","anchor":{"id":"8888dcb4-b725-5c58-abe7-96cfcb8ab970","slug":"chut","text":"ชุด","meaning":"set / combo","pronunciation":"chút","categoryKey":"food","contextNote":"ชุด shows up in set menus, school uniforms, and clothing signs. On menus, it often means a fixed combo or meal set.","segments":[{"text":"ชุ","sound":"chu"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"04981577-f898-5f42-ab6b-336cc3b526a5","key":"word-0e0a-0e32","text":"ชา","meaning":"tea","pronunciation":"chaa","categoryKey":"food","segments":[{"text":"ชา","sound":"chaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"6fef4f01-e1de-53f6-aa34-34c060d1b847","key":"word-0e0a-0e21","text":"ชม","meaning":"to admire","pronunciation":"chom","categoryKey":"daily","segments":[{"text":"ชม","sound":"chom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"5cded218-1a29-5f43-aa86-0333a6b83802","key":"word-0e0a-0e32-0e21","text":"ชาม","meaning":"bowl","pronunciation":"chaam","categoryKey":"food","segments":[{"text":"ชาม","sound":"chaam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f6f40f9d-5920-56c7-ad3c-f8c251f15074","key":"word-0e0a-0e34-0e14","text":"ชิด","meaning":"close together","pronunciation":"chit","categoryKey":"daily","segments":[{"text":"ชิด","sound":"chit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"123734b3-b6f6-5e91-ad26-b556d9a700d8","key":"word-0e14-0e38","text":"ดุ","meaning":"fierce / strict","pronunciation":"du","categoryKey":"daily","segments":[{"text":"ดุ","sound":"du"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"55b20bc1-ad75-526e-a9b8-5e84c53169f6","key":"word-0e25-0e38-0e01","text":"ลุก","meaning":"to get up","pronunciation":"luk","categoryKey":"daily","segments":[{"text":"ลุก","sound":"luk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"0faee178-a297-58d6-a92a-2a8f533b4991","key":"word-0e1a-0e38-0e01","text":"บุก","meaning":"to charge in","pronunciation":"buk","categoryKey":"daily","segments":[{"text":"บุก","sound":"buk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"a4a954e0-6ba3-5292-a173-5ad05f9964ce","key":"word-0e19-0e38-0e48-0e21","text":"นุ่ม","meaning":"soft","pronunciation":"num","categoryKey":"daily","segments":[{"text":"นุ่ม","sound":"num"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"85fd9b41-dc44-5bee-a89e-eba19102c6fe","key":"word-0e15-0e25-0e01","text":"ตลก","meaning":"funny","pronunciation":"dta-lok","categoryKey":"daily","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลก","sound":"lok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"f1c203bb-50b5-5872-a1b8-40cdaae0eb02","key":"word-0e15-0e25-0e32-0e14","text":"ตลาด","meaning":"market","pronunciation":"dta-laat","categoryKey":"place","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลาด","sound":"laat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"6a66a60f-c509-56f7-a54b-bd44a4028c40","key":"word-0e21-0e49-0e32","text":"ม้า","meaning":"horse","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"ม้า","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"63417404-20b6-5c86-a755-817318929a4c","key":"word-0e23-0e49-0e32-0e19","text":"ร้าน","meaning":"shop","pronunciation":"raan","categoryKey":"place","segments":[{"text":"ร้าน","sound":"raan"}],"metadata":{"sourceType":"real"}}}],"newGraphemes":[{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"a57ca296-4754-50f0-aad0-9856fff5c81d","text":"ุ","kind":"vowel","romanization":"u","pronunciationHint":"short \"u\" as in \"put\"","mnemonic":"ุ is the short u mark tucked under the consonant. Low on the page and short in sound: use it for the quick u in ชุด.","position":"below","details":{},"tags":[]}],"reviewGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tags":[]}],"rules":[{"id":"215881f9-c7b2-522c-aaea-b676d1f481a5","key":"short-u-below","name":"Short ุ Sits Below","shortDescription":"The short u vowel is written below the consonant you pronounce first","explanation":"Thai keeps asking you to scan vertically. In ชุด, the consonant ช comes first and the short vowel ุ is tucked underneath, so you read chu before the final consonant closes the syllable.","examples":[{"text":"ชุ = chu"},{"text":"ชุด = chút"}]},{"id":"707d8403-783a-58bc-a40e-f63cb7a936d5","key":"dead-syllable-stop","name":"Short Vowels Feel Clipped in Closed Syllables","shortDescription":"A short vowel plus a final stop makes the whole word feel quick and closed","explanation":"ชุด feels short because the vowel is short and the final consonant is stopped. This clipped rhythm shows up in lots of practical Thai words on menus and signs.","examples":[{"text":"ชุด = chút"},{"text":"มุด = mút"}]}],"drills":[{"id":"3618386b-665b-5416-a461-d0ef90065f36","key":"chut-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"ch\" sound?","payload":{},"options":[{"text":"ช","isCorrect":true},{"text":"ส"},{"text":"บ"},{"text":"ร"}]},{"id":"d59be859-7c84-5a9e-a350-e26e03ab8e12","key":"chut-drill-02-recognize","type":"recognize","prompt":"Which vowel is written below the consonant?","payload":{},"options":[{"text":"ุ","isCorrect":true},{"text":"ิ"},{"text":"า"},{"text":"แ"}]},{"id":"477d26d8-9e21-5d7c-a3c0-a8424c722db5","key":"chut-drill-03-match","type":"match","prompt":"What does ชุด mean on a menu?","payload":{},"options":[{"text":"set / combo","isCorrect":true},{"text":"fresh"},{"text":"rice"},{"text":"to fly"}]},{"id":"6e35c2ec-6361-5a90-a52b-2b9af1fc07a5","key":"chut-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"set / combo\"?","payload":{},"options":[{"text":"ชุด","isCorrect":true},{"text":"ชาด"},{"text":"สด"},{"text":"ชดุ"}]},{"id":"f533d512-ef1d-59d1-a42b-a53b713e4eeb","key":"chut-drill-05-sound","type":"sound","prompt":"How does the final ด sound in ชุด?","payload":{},"options":[{"text":"d"},{"text":"t","isCorrect":true},{"text":"n"},{"text":"silent"}]}]}}'::jsonb, '7ab5423b022c91afec5c5a575dc6e84eec4183028fcae21c5149e1f43cbd9ad9', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('3785d71c-3918-5276-ad7b-6f6d07fa48c9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'fb4954f1-e326-56e2-a3d1-b4132b60e254'::uuid, 'sip', 9, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"fb4954f1-e326-56e2-a3d1-b4132b60e254","slug":"sip","lessonOrdinal":9,"stage":4,"title":"สิบ — Read Prices Faster","anchor":{"id":"c7f7eeee-be9c-59ec-a5ca-e993cf2d61c4","slug":"sip","text":"สิบ","meaning":"ten","pronunciation":"sìp","categoryKey":"sign","contextNote":"สิบ helps with prices, receipts, and quantity labels. Even one number word gives you real payoff in markets and transit.","segments":[{"text":"สิ","sound":"si"},{"text":"บ","sound":"p"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"19e88090-7511-52e2-a642-6b7417be5672","key":"word-0e2a-0e35","text":"สี","meaning":"color","pronunciation":"sii","categoryKey":"daily","segments":[{"text":"สี","sound":"sii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"cc6952b1-247e-5295-a69b-5c101bbac32e","key":"word-0e2a-0e32-0e21","text":"สาม","meaning":"three","pronunciation":"saam","categoryKey":"sign","segments":[{"text":"สาม","sound":"saam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"78a836eb-7d55-50ee-a937-1d175bbb96a6","key":"word-0e2a-0e49-0e21","text":"ส้ม","meaning":"orange","pronunciation":"som","categoryKey":"food","segments":[{"text":"ส้ม","sound":"som"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"3cbedc7a-a552-5f04-a1d8-dcf9b13223e4","key":"word-0e2a-0e19-0e38-0e01","text":"สนุก","meaning":"fun","pronunciation":"sa-nuk","categoryKey":"daily","segments":[{"text":"สะ","sound":"sa"},{"text":"นุก","sound":"nuk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"8f5f0a36-8b88-5899-a374-902c8ccc7d85","key":"word-0e2a-0e38-0e14","text":"สุด","meaning":"most / end","pronunciation":"sut","categoryKey":"daily","segments":[{"text":"สุด","sound":"sut"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"80d07517-ec44-52c4-a8c0-32a13e8b620f","key":"word-0e2a-0e14","text":"สด","meaning":"fresh","pronunciation":"sot","categoryKey":"food","segments":[{"text":"สด","sound":"sot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"9bf27553-37c4-5eb4-a25f-3cd94a769825","key":"word-0e2a-0e21-0e38-0e14","text":"สมุด","meaning":"notebook","pronunciation":"sa-mut","categoryKey":"sign","segments":[{"text":"สะ","sound":"sa"},{"text":"มุด","sound":"mut"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"d9a39e42-58de-53a3-a768-752c144b9c6b","key":"word-0e2a-0e32-0e21-0e2a-0e34-0e1a","text":"สามสิบ","meaning":"thirty","pronunciation":"saam sip","categoryKey":"sign","segments":[{"text":"สาม","sound":"saam"},{"text":"สิบ","sound":"sip"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"79b85f07-1c04-5cf4-aedc-10e88083faf6","key":"word-0e2a-0e49-0e21-0e2a-0e14","text":"ส้มสด","meaning":"fresh oranges","pronunciation":"som sot","categoryKey":"food","segments":[{"text":"ส้ม","sound":"som"},{"text":"สด","sound":"sot"}],"metadata":{"sourceType":"phrase"}}}],"newGraphemes":[{"id":"ae26196d-7a39-57e3-a8c4-061567bf9167","text":"ส","kind":"consonant","romanization":"s","pronunciationHint":"s as in \"sun\"","mnemonic":"ส is ส เสือ (sor suea, tiger). The pointed, striped-looking shape can cue a tiger, and เสือ starts with the crisp s sound.","position":"standalone","details":{"class":"high"},"tags":[]}],"reviewGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"a57ca296-4754-50f0-aad0-9856fff5c81d","text":"ุ","kind":"vowel","romanization":"u","pronunciationHint":"short \"u\" as in \"put\"","mnemonic":"ุ is the short u mark tucked under the consonant. Low on the page and short in sound: use it for the quick u in ชุด.","position":"below","details":{},"tags":[]}],"rules":[{"id":"1a204ee8-b537-5026-a80e-84c60be7b87d","key":"initial-s-sound","name":"Initial ส Gives You S","shortDescription":"At the start of a syllable, ส is a clean s sound","explanation":"Thai has several letters that can map to an s-like sound, but you do not need them all at once. Start with ส because it appears constantly in useful words, labels, and polite formulas.","examples":[{"text":"สิบ = sìp"},{"text":"สด = sòt"}]},{"id":"a81aec16-221e-590d-a79d-ca348451a472","key":"final-b-to-p","name":"Final บ Closes as P","shortDescription":"At the end of a word, บ does not stay a full b sound","explanation":"Like several Thai final consonants, บ gets clipped at the end of a syllable. In สิบ, your lips close for p without the full released English b sound.","examples":[{"text":"สิบ = sìp"},{"text":"บัส = bát"}]}],"drills":[{"id":"acc21424-6128-5919-a890-2a2c4ac0c784","key":"sip-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"s\" sound?","payload":{},"options":[{"text":"ส","isCorrect":true},{"text":"ช"},{"text":"ร"},{"text":"บ"}]},{"id":"f12da006-4547-53fe-ac15-725c30c4746c","key":"sip-drill-02-match","type":"match","prompt":"What does สิบ mean?","payload":{},"options":[{"text":"rice"},{"text":"shop"},{"text":"ten","isCorrect":true},{"text":"mother"}]},{"id":"106c959c-12be-57d5-ae47-989845755e78","key":"sip-drill-03-sound","type":"sound","prompt":"Why does final บ in สิบ sound like p?","payload":{},"options":[{"text":"Thai drops all final consonants"},{"text":"final บ closes as p in Thai","isCorrect":true},{"text":"the tone mark changes it"},{"text":"the vowel makes it silent"}]},{"id":"02af70d4-c198-587f-aa33-3b8717f34737","key":"sip-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"ten\"?","payload":{},"options":[{"text":"สิบ","isCorrect":true},{"text":"บิส"},{"text":"สด"},{"text":"สบิ"}]},{"id":"df92c923-c1a1-513a-a6ab-ea02c5bf16df","key":"sip-drill-05-sound","type":"sound","prompt":"How do you pronounce สิบ?","payload":{},"options":[{"text":"sib"},{"text":"sii"},{"text":"sip","isCorrect":true},{"text":"sup"}]}]}}'::jsonb, '348b2920f7029e8661bfe76aa132dbd0a5713973041825575371b461249f7b00', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a254cee8-2991-5cd1-aac1-883d929d4cd7'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '489857d0-a162-5afa-a7bb-c797b5761864'::uuid, 'khao', 10, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"489857d0-a162-5afa-a7bb-c797b5761864","slug":"khao","lessonOrdinal":10,"stage":5,"title":"ข้าว — A Survival Food Word","anchor":{"id":"cc47d33e-ee3d-50dc-a6ce-b3d61029996d","slug":"khao","text":"ข้าว","meaning":"rice","pronunciation":"khâao","categoryKey":"food","contextNote":"ข้าว is one of the highest-value food words in Thailand. It appears on menus, in meal names, and in everyday conversation.","segments":[{"text":"ข้า","sound":"khaa"},{"text":"ว","sound":"w glide"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"49d998d8-81d7-509b-ab5c-b6fab9b2e9c3","key":"word-0e02-0e27-0e32","text":"ขวา","meaning":"right side","pronunciation":"khwaa","categoryKey":"sign","segments":[{"text":"ขวา","sound":"khwaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"ad5f5493-0875-5b14-a014-ed4c5d2d7a8a","key":"word-0e02-0e48-0e32-0e27","text":"ข่าว","meaning":"news","pronunciation":"khaao","categoryKey":"sign","segments":[{"text":"ข่าว","sound":"khaao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"4b277ab9-99f9-523d-a6b3-895443e63944","key":"word-0e02-0e32-0e27","text":"ขาว","meaning":"white","pronunciation":"khaao","categoryKey":"daily","segments":[{"text":"ขาว","sound":"khaao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"8a92dbf1-5054-53f5-a5a4-6a75e342a6ee","key":"word-0e02-0e27-0e14","text":"ขวด","meaning":"bottle","pronunciation":"khuat","categoryKey":"daily","segments":[{"text":"ขวด","sound":"khuat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"ecee6e47-ebbb-5dae-aad2-38cfec474745","key":"word-0e02-0e32","text":"ขา","meaning":"leg","pronunciation":"khaa","categoryKey":"daily","segments":[{"text":"ขา","sound":"khaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"5d489b6f-4e4d-5924-a401-f2c555ed94f8","key":"word-0e02-0e21","text":"ขม","meaning":"bitter","pronunciation":"khom","categoryKey":"food","segments":[{"text":"ขม","sound":"khom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"1621be98-12f7-5c95-a927-eb04c7ccbdbd","key":"word-0e02-0e32-0e14","text":"ขาด","meaning":"to lack / be torn","pronunciation":"khaat","categoryKey":"daily","segments":[{"text":"ขาด","sound":"khaat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"27f8a8b4-3ade-5533-a6bc-5a7bb7fdd7f4","key":"word-0e27-0e32-0e14","text":"วาด","meaning":"to draw","pronunciation":"waat","categoryKey":"daily","segments":[{"text":"วาด","sound":"waat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"04f9ae15-2e7a-57b1-a70e-d8c7c10f10f7","key":"word-0e27-0e48-0e32","text":"ว่า","meaning":"to say / that","pronunciation":"waa","categoryKey":"daily","segments":[{"text":"ว่า","sound":"waa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"0f38335e-0377-50b9-a08c-34d41e5821ac","key":"word-0e14-0e32-0e27","text":"ดาว","meaning":"star","pronunciation":"daao","categoryKey":"daily","segments":[{"text":"ดาว","sound":"daao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"4380bfe9-6e97-500e-afa1-c84528ddd28c","key":"word-0e2a-0e27-0e19","text":"สวน","meaning":"garden / park","pronunciation":"suan","categoryKey":"place","segments":[{"text":"สวน","sound":"suan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"bb650142-5eea-5cbe-a533-eaf8abae663d","key":"word-0e02-0e49-0e32-0e27-0e02-0e32-0e27","text":"ข้าวขาว","meaning":"white rice","pronunciation":"khaao khaao","categoryKey":"food","segments":[{"text":"ข้าว","sound":"khaao"},{"text":"ขาว","sound":"khaao"}],"metadata":{"sourceType":"phrase"}}}],"newGraphemes":[{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tags":[]}],"reviewGraphemes":[{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]}],"rules":[{"id":"71da4ee2-bbc8-5047-a6bf-bbfd13816bfc","key":"kh-vs-k","name":"ข Adds Air to K","shortDescription":"ข is not the same as ก; it has a stronger puff of air","explanation":"Thai distinguishes plain k sounds from aspirated kh sounds. If you hold your hand in front of your mouth, ข pushes out a little air in a way ก does not.","examples":[{"text":"กา = gaa"},{"text":"ข่าว = khàao"},{"text":"ข้าว = khâao"}]},{"id":"52b3fcea-a418-58db-ad81-2054c133fba1","key":"aaw-glide","name":"ว Can Help Build a Vowel Glide","shortDescription":"In words like ข้าว, ว helps shape the ending vowel sound instead of behaving like a full separate consonant","explanation":"Not every written consonant is heard as a clean standalone consonant. In ข้าว, ว helps form the -าว ending, so you hear a smooth glide rather than a sharp final w.","examples":[{"text":"ข่าว = khàao"},{"text":"ข้าว = khâao"}]}],"drills":[{"id":"9277e873-bfa3-53f7-a26f-72549d58727a","key":"khao-drill-01-recognize","type":"recognize","prompt":"Which letter gives the aspirated \"kh\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ข","isCorrect":true},{"text":"บ"},{"text":"ห"}]},{"id":"72b362c6-5874-5eb5-ae33-d322cad13016","key":"khao-drill-02-recognize","type":"recognize","prompt":"Which letter helps build the -าว ending in ข้าว?","payload":{},"options":[{"text":"น"},{"text":"ว","isCorrect":true},{"text":"ร"},{"text":"ล"}]},{"id":"c744f172-4cd7-5f24-a563-6dbefb6498ad","key":"khao-drill-03-match","type":"match","prompt":"What does ข้าว mean?","payload":{},"options":[{"text":"rice","isCorrect":true},{"text":"fresh"},{"text":"ten"},{"text":"mother"}]},{"id":"a54b1113-2c41-5e38-a0a6-f4ed6ce3b6f3","key":"khao-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"rice\"?","payload":{},"options":[{"text":"ข้าว","isCorrect":true},{"text":"ขาว"},{"text":"ข้า"},{"text":"ขน"}]},{"id":"62a04a09-d6ca-5d0c-a968-c3a5a904b052","key":"khao-drill-05-sound","type":"sound","prompt":"What is the key difference between ก and ข?","payload":{},"options":[{"text":"ก is nasal and ข is silent"},{"text":"ข has a puff of air and ก does not","isCorrect":true},{"text":"they sound the same"},{"text":"ข is only used at the end of words"}]}]}}'::jsonb, '1170ed354b10d63b0a44abe3b703f8f21a98d6c8eaabda41d8d98ea6bf134cc9', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a606d673-c171-56e5-a0a8-09a4dee06c2f'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '6a8b53e3-50a0-5db3-a089-a15c56bc01c6'::uuid, 'moo', 11, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"6a8b53e3-50a0-5db3-a089-a15c56bc01c6","slug":"moo","lessonOrdinal":11,"stage":5,"title":"หมู — Leading ห in a Real Menu Word","anchor":{"id":"c771541d-bc22-55d6-ade9-52b9d986cfe2","slug":"moo","text":"หมู","meaning":"pork","pronunciation":"mǔu","categoryKey":"food","contextNote":"หมู is everywhere on Thai menus. It is also the cleanest early example of the leading-ห pattern that learners need sooner rather than later.","segments":[{"text":"ห","sound":"leading h"},{"text":"มู","sound":"muu"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"8add2650-ea68-509f-ae3d-8c35db8b7b59","key":"word-0e2b-0e39","text":"หู","meaning":"ear","pronunciation":"huu","categoryKey":"daily","segments":[{"text":"หู","sound":"huu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8c79ebe5-9b38-5d70-a534-b40b909e194e","key":"word-0e2b-0e21-0e32","text":"หมา","meaning":"dog","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"หมา","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"f4755169-67ed-53b6-ac5f-8f9c0b01cc4f","key":"word-0e2b-0e32","text":"หา","meaning":"to look for","pronunciation":"haa","categoryKey":"daily","segments":[{"text":"หา","sound":"haa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f12c3344-3a1f-53c0-a42e-0f068f47080c","key":"word-0e23-0e39-0e49","text":"รู้","meaning":"to know","pronunciation":"ruu","categoryKey":"daily","segments":[{"text":"รู้","sound":"ruu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"598027dc-4153-5c7b-adcd-e5c1fecc9140","key":"word-0e14-0e39","text":"ดู","meaning":"to watch","pronunciation":"duu","categoryKey":"daily","segments":[{"text":"ดู","sound":"duu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"cda49f45-c2e6-58b2-ad64-ce6066aeb0fa","key":"word-0e2b-0e34-0e27","text":"หิว","meaning":"hungry","pronunciation":"hiw","categoryKey":"daily","segments":[{"text":"หิว","sound":"hiw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"52c43174-6f7b-563d-a0cc-490c2598a58a","key":"word-0e2b-0e21-0e14","text":"หมด","meaning":"all gone","pronunciation":"mot","categoryKey":"daily","segments":[{"text":"หมด","sound":"mot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"0edbc717-9d7f-5069-ad5a-fd22c5ec3c54","key":"word-0e25-0e39-0e01","text":"ลูก","meaning":"child","pronunciation":"luuk","categoryKey":"daily","segments":[{"text":"ลูก","sound":"luuk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"7c54b99c-c014-5d9d-abe1-b92bbc15d050","key":"word-0e15-0e39-0e49","text":"ตู้","meaning":"cabinet","pronunciation":"tuu","categoryKey":"place","segments":[{"text":"ตู้","sound":"tuu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"cbbf92fe-74b0-5d46-a1d9-9b5e2e19cff2","key":"word-0e2a-0e39-0e49","text":"สู้","meaning":"to fight","pronunciation":"suu","categoryKey":"daily","segments":[{"text":"สู้","sound":"suu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c7fa958a-64c3-52ea-a4ba-845f0a7feb4e","key":"word-0e2b-0e27-0e32-0e19","text":"หวาน","meaning":"sweet","pronunciation":"waan","categoryKey":"food","segments":[{"text":"หวาน","sound":"waan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8968cae3-fe97-5863-af6c-6932e5f2d4fb","key":"word-0e2b-0e49-0e32-0e21","text":"ห้าม","meaning":"forbidden / do not","pronunciation":"haam","categoryKey":"sign","segments":[{"text":"ห้าม","sound":"haam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"7ba77c91-000c-5258-aff4-7680dd07e122","key":"word-0e2b-0e34-0e27-0e21-0e32-0e01","text":"หิวมาก","meaning":"very hungry","pronunciation":"hiw maak","categoryKey":"daily","segments":[{"text":"หิว","sound":"hiw"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"1aa8932e-9563-5621-aaec-4477efb463ff","key":"word-0e2b-0e21-0e39-0e2a-0e14","text":"หมูสด","meaning":"fresh pork","pronunciation":"muu sot","categoryKey":"food","segments":[{"text":"หมู","sound":"muu"},{"text":"สด","sound":"sot"}],"metadata":{"sourceType":"phrase"}}}],"newGraphemes":[{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"6cbd6547-63c8-52cd-a2e5-378aa42e3e46","text":"ู","kind":"vowel","romanization":"uu","pronunciationHint":"long \"oo\" as in \"food\"","mnemonic":"ู is the long uu mark below the consonant. It is like ุ with a longer lower tail, so let the oo sound run longer.","position":"below","details":{},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tags":[]}],"rules":[{"id":"62ade15b-2ecf-5726-a1dd-6689ff8c548e","key":"leading-h-pattern","name":"Leading ห Changes the Tone Pattern","shortDescription":"In common words like หมู, ห helps a following low consonant behave differently","explanation":"This is one of the Thai chunks worth learning as a whole. In words like หมู, the ห is not there to give you a full h sound before every letter. It helps control the syllable pattern of the low consonant that follows.","examples":[{"text":"หมู = mǔu"},{"text":"หมอ = mǎaw"}]},{"id":"d5b18e8e-9a1e-5ea5-a808-651961f8dfb4","key":"long-uu-below","name":"Long ู Sits Below","shortDescription":"The long oo vowel is written below the consonant","explanation":"Thai uses the space below the line too. In หมู and หู, the vowel ู sits under the consonant and gives you a long oo sound.","examples":[{"text":"หมู = mǔu"},{"text":"ดู = duu"}]}],"drills":[{"id":"aee4f232-92da-5ff9-ab9a-4f6159e0013a","key":"moo-drill-01-recognize","type":"recognize","prompt":"Which letter is the leading ห in หมู?","payload":{},"options":[{"text":"ห","isCorrect":true},{"text":"ม"},{"text":"ข"},{"text":"อ"}]},{"id":"88afeac6-4549-51f2-a692-0619b08828d8","key":"moo-drill-02-recognize","type":"recognize","prompt":"Which vowel makes the long \"oo\" sound?","payload":{},"options":[{"text":"ุ"},{"text":"ู","isCorrect":true},{"text":"ิ"},{"text":"ี"}]},{"id":"8b2a3c3c-c41d-5097-afcd-6ae79c70b553","key":"moo-drill-03-match","type":"match","prompt":"What does หมู mean?","payload":{},"options":[{"text":"pork","isCorrect":true},{"text":"rice"},{"text":"shop"},{"text":"food"}]},{"id":"de1ce793-e310-5856-a6da-cabd69b2e3d9","key":"moo-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"pork\"?","payload":{},"options":[{"text":"หมู","isCorrect":true},{"text":"มู"},{"text":"หมา"},{"text":"ขู"}]},{"id":"81bb588d-fda4-5b93-ac8d-d7b10794035c","key":"moo-drill-05-sound","type":"sound","prompt":"Why is ห useful in words like หมู?","payload":{},"options":[{"text":"It adds a final consonant"},{"text":"It changes the tone pattern of the low consonant that follows","isCorrect":true},{"text":"It marks plural"},{"text":"It makes the vowel longer all by itself"}]}]}}'::jsonb, 'ef0fc941b0d0d80bde29de0b16a34bff4ee302546ee396099a78215359e0d1a7', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('96311bdb-d7ff-5120-a392-2a9046da278b'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'e387c914-ad75-5a7c-a972-cf079418042d'::uuid, 'ahan', 12, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"e387c914-ad75-5a7c-a972-cf079418042d","slug":"ahan","lessonOrdinal":12,"stage":5,"title":"อาหาร — Silent Carrier, Useful Sign","anchor":{"id":"01409ff0-7f6d-54f3-ab1e-8e428d0ca405","slug":"ahan","text":"อาหาร","meaning":"food","pronunciation":"aa-hǎan","categoryKey":"food","contextNote":"อาหาร appears on restaurant signs, food courts, and delivery labels. Once you can read ร้านอาหาร, the street starts feeling more legible.","segments":[{"text":"อา","sound":"aa"},{"text":"หา","sound":"hǎa"},{"text":"ร","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c0ae7fff-a846-5198-af67-4174b5a833ab","key":"word-0e2d-0e2d-0e01","text":"ออก","meaning":"to exit / go out","pronunciation":"awk","categoryKey":"sign","segments":[{"text":"ออก","sound":"awk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"46902c0d-543a-55e1-ab8a-e5d2c299ab39","key":"word-0e02-0e2d","text":"ขอ","meaning":"to ask for","pronunciation":"khaaw","categoryKey":"daily","segments":[{"text":"ขอ","sound":"khaaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"7debb9fb-b969-59fa-a6de-bda8eb99829c","key":"word-0e0a-0e2d-0e1a","text":"ชอบ","meaning":"to like","pronunciation":"chaawp","categoryKey":"daily","segments":[{"text":"ชอบ","sound":"chaawp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"e1949758-58f1-594e-a1c4-fff2d139bc20","key":"word-0e23-0e49-0e2d-0e19","text":"ร้อน","meaning":"hot","pronunciation":"raawn","categoryKey":"daily","segments":[{"text":"ร้อน","sound":"raawn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"be7afec8-972c-5cc1-a833-fa707d436cd8","key":"word-0e23-0e2d","text":"รอ","meaning":"to wait","pronunciation":"raaw","categoryKey":"daily","segments":[{"text":"รอ","sound":"raaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"f6aa72e4-6ec4-5756-a920-7e868f166d6d","key":"word-0e1a-0e2d-0e01","text":"บอก","meaning":"to tell","pronunciation":"baawk","categoryKey":"daily","segments":[{"text":"บอก","sound":"baawk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"1bf9cebe-27d0-5606-a9f6-96d3eaf3b7fb","key":"word-0e2b-0e21-0e2d","text":"หมอ","meaning":"doctor","pronunciation":"maaw","categoryKey":"daily","segments":[{"text":"หมอ","sound":"maaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"cae64235-6767-58f0-ac6b-dd2e62c23141","key":"word-0e14-0e2d-0e01","text":"ดอก","meaning":"flower","pronunciation":"daawk","categoryKey":"daily","segments":[{"text":"ดอก","sound":"daawk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"a1b845ac-b7ec-57bc-ae29-1151128172f0","key":"word-0e2b-0e2d-0e21","text":"หอม","meaning":"fragrant","pronunciation":"haawm","categoryKey":"daily","segments":[{"text":"หอม","sound":"haawm"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"7f0cf283-d9f0-5d82-a968-3c8605cfb741","key":"word-0e15-0e2d-0e1a","text":"ตอบ","meaning":"to answer","pronunciation":"dtaawp","categoryKey":"daily","segments":[{"text":"ตอบ","sound":"dtaawp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"6e3d61d8-c2a8-5d55-aaff-4512b69e43da","key":"word-0e2d-0e49-0e27-0e19","text":"อ้วน","meaning":"fat / overweight","pronunciation":"uuan","categoryKey":"daily","segments":[{"text":"อ้วน","sound":"uuan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"038d8c5a-b113-5036-afe0-83c560b4e838","key":"word-0e02-0e2d-0e0a-0e32","text":"ขอชา","meaning":"may I have tea","pronunciation":"khaaw chaa","categoryKey":"food","segments":[{"text":"ขอ","sound":"khaaw"},{"text":"ชา","sound":"chaa"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"f7ae2242-6833-5d1c-a43c-9d4c8c3afd39","key":"word-0e0a-0e2d-0e1a-0e21-0e32-0e01","text":"ชอบมาก","meaning":"like very much","pronunciation":"chaawp maak","categoryKey":"daily","segments":[{"text":"ชอบ","sound":"chaawp"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}}],"newGraphemes":[{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tags":[]}],"reviewGraphemes":[{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tags":[]}],"rules":[{"id":"12476104-aabd-52e5-ad0e-4994d23aec74","key":"silent-carrier","name":"อ Can Carry a Vowel Silently","shortDescription":"Thai still wants a consonant slot even when the syllable begins with a vowel sound","explanation":"In อาหาร, the first syllable sounds like aa, but Thai still writes a consonant letter to hold that opening vowel. อ acts as the carrier without adding a strong sound of its own.","examples":[{"text":"อา = aa"},{"text":"อาหาร = aa-hǎan"}]},{"id":"b144050a-1ef9-53f3-ae3c-d669fc4571f3","key":"final-r-to-n","name":"Final ร Often Sounds Like \"n\"","shortDescription":"At the end of a syllable, ร is often heard as \"n\" instead of a full r","explanation":"Thai final consonants do not always match their initial sounds. In อาหาร, the final ร is not read as a strong r. It closes the word with an n-like ending instead.","examples":[{"text":"อาหาร = aa-hǎan"},{"text":"สาร = sǎan"}]}],"drills":[{"id":"1b4dcf0d-6c4b-508e-a299-8c8d60f12f33","key":"ahan-drill-01-recognize","type":"recognize","prompt":"Which letter is the silent carrier?","payload":{},"options":[{"text":"อ","isCorrect":true},{"text":"ห"},{"text":"ร"},{"text":"ว"}]},{"id":"f802dbbd-32dc-5fc5-a3ec-03038e9fe5c8","key":"ahan-drill-02-match","type":"match","prompt":"What does อาหาร mean?","payload":{},"options":[{"text":"food","isCorrect":true},{"text":"set menu"},{"text":"mother"},{"text":"to fly"}]},{"id":"143f1ddd-6c90-53a5-aca3-03d10ecb8226","key":"ahan-drill-03-spot","type":"spot","prompt":"Which Thai spelling means \"food\"?","payload":{},"options":[{"text":"อาหาร","isCorrect":true},{"text":"หารอา"},{"text":"หมู"},{"text":"ผัด"}]},{"id":"afd544e1-be46-5ddc-a9bb-a97a33eee37a","key":"ahan-drill-04-sound","type":"sound","prompt":"How does the final ร sound in อาหาร?","payload":{},"options":[{"text":"r"},{"text":"l"},{"text":"n","isCorrect":true},{"text":"silent"}]},{"id":"b917b9b7-a124-51ac-a09a-ac2df18d12cd","key":"ahan-drill-05-recognize","type":"recognize","prompt":"Why does อาหาร begin with อ?","payload":{},"options":[{"text":"It marks plural"},{"text":"Thai needs a consonant slot, so อ carries the opening vowel","isCorrect":true},{"text":"It is only decorative"},{"text":"It always means the word is formal"}]}]}}'::jsonb, 'eb87389c98afd206e52854afc1159efa65f81bec8527736a5d8ef10bd893002e', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('f41342dd-6644-59cb-a627-4f879f99628e'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '227b7204-c818-5c7c-ad68-654e72285cd6'::uuid, 'phat', 13, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"227b7204-c818-5c7c-ad68-654e72285cd6","slug":"phat","lessonOrdinal":13,"stage":5,"title":"ผัด — Unlock Stir-Fry Words","anchor":{"id":"d2faba91-170e-5cef-ad0b-7f3a04ac6143","slug":"phat","text":"ผัด","meaning":"stir-fry","pronunciation":"phàt","categoryKey":"food","contextNote":"ผัด appears on some of the most common Thai dishes, from ผัดไทย to vegetable stir-fries. It is one of the highest-value cooking words you can learn.","segments":[{"text":"ผั","sound":"pha"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"b0c734f8-b446-5b48-ab6f-188e3678a636","key":"word-0e1c-0e31-0e01","text":"ผัก","meaning":"vegetables","pronunciation":"phak","categoryKey":"food","segments":[{"text":"ผัก","sound":"phak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"dad63552-fe4a-55e4-a8e1-9e0804d5a448","key":"word-0e1c-0e21","text":"ผม","meaning":"I / hair","pronunciation":"phom","categoryKey":"daily","segments":[{"text":"ผม","sound":"phom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"07330a77-9112-51d7-a364-42c132bc7614","key":"word-0e23-0e31-0e01","text":"รัก","meaning":"to love","pronunciation":"rak","categoryKey":"daily","segments":[{"text":"รัก","sound":"rak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"5d73dcdf-4d91-5d90-ad80-d7c6c4d1c3a7","key":"word-0e27-0e31-0e19","text":"วัน","meaning":"day","pronunciation":"wan","categoryKey":"sign","segments":[{"text":"วัน","sound":"wan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"60e93954-b63a-52aa-a0ea-881bda6a7364","key":"word-0e21-0e31-0e19","text":"มัน","meaning":"it / oily","pronunciation":"man","categoryKey":"daily","segments":[{"text":"มัน","sound":"man"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"2ef7151f-6563-5b7b-a5e9-fe8de6c75f66","key":"word-0e27-0e31-0e14","text":"วัด","meaning":"temple / to measure","pronunciation":"wat","categoryKey":"place","segments":[{"text":"วัด","sound":"wat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"a9b39b92-ff0e-56e0-a99a-6e0afc2df519","key":"word-0e23-0e31-0e1a","text":"รับ","meaning":"to receive","pronunciation":"rap","categoryKey":"daily","segments":[{"text":"รับ","sound":"rap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"47638a79-db13-5297-ad71-1c26b39d6a22","key":"word-0e02-0e31-0e1a","text":"ขับ","meaning":"to drive","pronunciation":"khap","categoryKey":"daily","segments":[{"text":"ขับ","sound":"khap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"0c3d4a24-2b48-581a-a296-6f0b7480f539","key":"word-0e2b-0e31-0e27","text":"หัว","meaning":"head","pronunciation":"hua","categoryKey":"daily","segments":[{"text":"หัว","sound":"hua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"cb1240ca-1d7b-5509-a6e2-d53911ecf508","key":"word-0e15-0e31-0e1a","text":"ตับ","meaning":"liver","pronunciation":"dtap","categoryKey":"food","segments":[{"text":"ตับ","sound":"dtap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"05a466bf-5f31-5bfa-af06-d11c752c2595","key":"word-0e2a-0e31-0e49-0e19","text":"สั้น","meaning":"short","pronunciation":"san","categoryKey":"daily","segments":[{"text":"สั้น","sound":"san"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"ee58ba57-f2fb-5b14-a9da-e37e9d0f800f","key":"word-0e1c-0e49-0e32","text":"ผ้า","meaning":"cloth","pronunciation":"phaa","categoryKey":"daily","segments":[{"text":"ผ้า","sound":"phaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"d15b5e1e-de21-5f76-af19-397033576d45","key":"word-0e1c-0e35","text":"ผี","meaning":"ghost","pronunciation":"phii","categoryKey":"daily","segments":[{"text":"ผี","sound":"phii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"18d020b7-932a-5d37-a916-eb1cba31dc37","key":"word-0e15-0e31-0e27","text":"ตัว","meaning":"body / self","pronunciation":"dtua","categoryKey":"daily","segments":[{"text":"ตัว","sound":"dtua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"82fe7ab6-0023-50d4-a20c-cd5e249f5adc","key":"word-0e1c-0e31-0e14-0e1c-0e31-0e01","text":"ผัดผัก","meaning":"stir-fried vegetables","pronunciation":"phat phak","categoryKey":"food","segments":[{"text":"ผัด","sound":"phat"},{"text":"ผัก","sound":"phak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"ca72f102-44a9-518b-acc8-90b517fabec7","key":"word-0e1c-0e21-0e2b-0e34-0e27","text":"ผมหิว","meaning":"I am hungry","pronunciation":"phom hiw","categoryKey":"daily","segments":[{"text":"ผม","sound":"phom"},{"text":"หิว","sound":"hiw"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"3c992023-814d-5a7d-a46d-28107afdf750","key":"word-0e23-0e31-0e01-0e41-0e21-0e48","text":"รักแม่","meaning":"to love mom","pronunciation":"rak mae","categoryKey":"daily","segments":[{"text":"รัก","sound":"rak"},{"text":"แม่","sound":"mae"}],"metadata":{"sourceType":"phrase"}}}],"newGraphemes":[{"id":"da8975d2-f60a-59f9-a1d2-f55df44b6bfa","text":"ผ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the start of \"photo\" without the f sound","mnemonic":"ผ is ผ ผึ้ง (phor phueng, bee). Picture the open shape as wings and body; ผึ้ง starts with the puffed ph sound.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tags":[]}],"rules":[{"id":"a760feb3-b11d-5a48-aa4b-dfb7b7a0c055","key":"ph-vs-b","name":"ผ Gives You an Airy Ph Sound","shortDescription":"ผ is not the same as บ; it starts with a stronger puff of air","explanation":"Thai distinguishes plain b/p-like sounds from aspirated ph sounds. In ผัด, you can feel a burst of air at the start that you do not get with บ.","examples":[{"text":"ผัด = phàt"},{"text":"ผัน = phan"}]},{"id":"80814a05-caf2-5ac2-afd4-5311e1cc970e","key":"short-a-above","name":"Short ั Sits Above","shortDescription":"The short a vowel is written above the consonant","explanation":"Thai uses a small mark above the consonant for the short a sound in words like ผัด. It is quicker and more clipped than the long right-side vowel า you learned earlier.","examples":[{"text":"ผัด = phàt"},{"text":"ผัน = phan"}]}],"drills":[{"id":"62ec9ab5-e2a5-5a39-afa3-ecd5bb5329e4","key":"phat-drill-01-recognize","type":"recognize","prompt":"Which letter makes the aspirated \"ph\" sound?","payload":{},"options":[{"text":"ผ","isCorrect":true},{"text":"บ"},{"text":"ห"},{"text":"ข"}]},{"id":"9f452601-a03f-5cae-adc1-7dd3fa1f3114","key":"phat-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the short \"a\" sound above the consonant?","payload":{},"options":[{"text":"ั","isCorrect":true},{"text":"า"},{"text":"แ"},{"text":"ุ"}]},{"id":"9439e02a-87e1-5211-a4e0-618142290f68","key":"phat-drill-03-match","type":"match","prompt":"What does ผัด mean?","payload":{},"options":[{"text":"stir-fry","isCorrect":true},{"text":"food court"},{"text":"shop"},{"text":"ten"}]},{"id":"d7f90549-40dd-5a16-a101-e7f33354bfaf","key":"phat-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"stir-fry\"?","payload":{},"options":[{"text":"ผัด","isCorrect":true},{"text":"ผาด"},{"text":"ผาก"},{"text":"ชุด"}]},{"id":"b9806e17-7198-5645-a174-7f5434e9b97c","key":"phat-drill-05-sound","type":"sound","prompt":"Which word shares the same ผั- opening as ผัด?","payload":{},"options":[{"text":"ผัก","isCorrect":true},{"text":"ข้าว"},{"text":"บิน"},{"text":"แม่"}]}]}}'::jsonb, 'a36a5a47092513757951eec5c7b1767511ebe31bf35dd0d0634c318078cea896', '2026-04-30T00:00:00+00:00'::timestamptz);

